export interface RawTournament {
  id: string;
  series: string;
  date: string;
  day: string;
  time: string;
  event: string;
  guarantee: string | null;
  entry: string | null;
  entryAmount: number | null;
  chips: string | null;
  levels: string | null;
  endOfReg: string | null;
  eventNumber: string | null;
  format: string | null;
  lateReg: string | null;
  gameType: string;
  isMultiDay: boolean;
  isTurbo: boolean;
  isBounty: boolean;
  isSatellite: boolean;
}

function parseEntry(entry: string | null): number | null {
  if (!entry) return null;
  const cleaned = entry.replace(/[$,]/g, "").trim();
  const num = parseFloat(cleaned);
  return isNaN(num) ? null : num;
}

function detectGameType(event: string): string {
  const upper = event.toUpperCase();
  if (upper.includes("PLO") || upper.includes("POT-LIMIT OMAHA") || upper.includes("OMAHA")) return "PLO/Omaha";
  if (upper.includes("STUD")) return "Stud";
  if (upper.includes("HORSE")) return "Mixed";
  if (upper.includes("TORSE")) return "Mixed";
  if (upper.includes("8-GAME") || upper.includes("MIXED") || upper.includes("DEALERS CHOICE") || upper.includes("NINE GAME") || upper.includes("RAZZ") || upper.includes("BADUGI") || upper.includes("LOWBALL") || upper.includes("TRIPLE DRAW") || upper.includes("LIMIT HOLD") || upper.includes("BIG O") || upper.includes("TOE")) return "Mixed";
  if (upper.includes("NO LIMIT HOLD") || upper.includes("NLH") || upper.includes("NO-LIMIT HOLD")) return "NLH";
  return "Other";
}

